Zrefaktoryzuj tę funkcję Node.js opartą na callbackach do async/await:

function getUser(id, callback) {
  db.query('SELECT * FROM users WHERE id = ?', [id], function(err, rows) {
    if (err) return callback(err);
    if (!rows.length) return callback(new Error('Nie znaleziono'));
    callback(null, rows[0]);
  });
}

Przejrzyj ten handler route Express pod kątem problemów bezpieczeństwa:

app.get('/api/users/:id', (req, res) => {
  const query = `SELECT * FROM users WHERE id = ${req.params.id}`;
  db.query(query).then(user => res.json(user));
});
